#include &lt;stdio.h&gt;
#include &lt;stdbool.h&gt;

// GCC/Clang intrinsic to hint the Branch Predictor
#define likely(x)   __builtin_expect(!!(x), 1)
#define unlikely(x) __builtin_expect(!!(x), 0)

void process_network_packet(bool is_corrupt) {
    // Instructs the compiler to push the error handling code far away 
    // so the 'hot path' (normal execution) stays in the L1 CPU cache.
    if (unlikely(is_corrupt)) {
        printf("Packet dropped.\n");
        return;
    }
    printf("Packet processed.\n");
}

#include &lt;stdio.h&gt;

typedef enum { STATE_INIT, STATE_RUN, STATE_STOP, STATE_FAULT } SysState;

void handle_state(SysState state) {
    // Values are 0,1,2,3 - compiler will generate an O(1) Jump Table
    switch (state) {
        case STATE_INIT:
            printf("Booting...\n");
            break;
        case STATE_RUN:
            printf("Running...\n");
            break;
        case STATE_STOP:
            printf("Halted.\n");
            break;
        case STATE_FAULT:
            // Intentional fallthrough to default
        default:
            printf("Emergency Shutdown!\n");
            break;
    }
}

// A notorious historical C optimization utilizing switch fallthrough 
// to unroll a loop. Valid C syntax, but highly discouraged today.
void copy_bytes(char *to, const char *from, int count) {
    int n = (count + 7) / 8;
    switch (count % 8) {
        case 0: do { *to++ = *from++;
        case 7:      *to++ = *from++;
        case 6:      *to++ = *from++;
        case 5:      *to++ = *from++;
        case 4:      *to++ = *from++;
        case 3:      *to++ = *from++;
        case 2:      *to++ = *from++;
        case 1:      *to++ = *from++;
                } while (--n > 0);
    }
}

