void clear_buffer(uint8_t *buffer, size_t length) {
    // Declaring the iterator inside the loop requires C99.
    // Using size_t guarantees the iterator can hold the maximum possible array size.
    for (size_t i = 0; i < length; i++) {
        buffer[i] = 0;
    }
}

