// Why use do-while(0) for a macro? It creates a safe block that requires 
// a terminating semicolon, allowing it to behave exactly like a real function call 
// when used inside if/else statements without braces.
#define SAFE_MACRO(x) do { \
    init_system(); \
    process(x); \
} while(0)

void test() {
    if (1)
        SAFE_MACRO(5); // The semicolon here belongs to the while(0), keeping syntax legal.
    else
        printf("Skipped.\n");
}

int read_file(const char* filepath) {
    // Guard Clause 1: Trap bad input instantly
    if (!filepath) {
        return -1; 
    }

    FILE *file = fopen(filepath, "r");
    // Guard Clause 2: Trap system failure
    if (!file) {
        return -2;
    }

    // By the time we reach here, we are guaranteed safe.
    // No nested pyramids required.
    process(file);
    fclose(file);
    return 0;
}

void parse_packets(Packet *packets, size_t count) {
    for (size_t i = 0; i < count; i++) {
        // Skip dropped packets and immediately jump back to 'i++'
        if (packets[i].status == DROPPED) {
            continue;
        }

        // The heavy lifting logic only runs on valid packets
        decode_payload(&packets[i]);
        dispatch(&packets[i]);
    }
}

int initialize_device() {
    void *mem1 = malloc(1024);
    if (!mem1) return -1;

    void *mem2 = malloc(2048);
    if (!mem2) {
        // If mem2 fails, we MUST free mem1 before returning.
        // We use goto to jump to the cleanup block.
        goto err_mem1;
    }

    if (init_hardware(mem1, mem2) < 0) {
        goto err_hw;
    }

    return 0; // Success

    // Single point of cleanup. Fallthrough architecture.
err_hw:
    free(mem2);
err_mem1:
    free(mem1);
    return -1;
}
